//uv1 = (uv1-0.5)*uAspect.yx + 0.5;
uv1 = mix(uv1,vUv,q20);


//uv1 += vec2 (sin(q14), cos(q14))*q21;
uv1 += vec2 (q25,q26);

uv3 = uv1;
uv2 = uv1-0.5;
uv1 = vec2 (4*length(uv2),2*q20*aTan2 (abs(uv2.y+q21/4),abs(uv2.x+q22/4))).yx;
uv1 = mix(uv1,uv3,q23);

arg = 4*(sat(8*abs(uv1.y-0.5)) * sat(8*abs(uv1.x-0.5-(q15*.7)))) ;
//arg = 64*(abs(uv1.y-0.5));

arg2 = pow(4/audioLowSmooth*length(cos((vUv + vec2((q7%16)/16,0))*3*3.1416)),2);

//arg = arg2;
ret = 1 - pow(arg,1);
ret = exp(-arg*2);




ret *= 2*normalize(texture(sampler_noise_hq,(uv1+q14/32)/16));
